/* Helper: index POIs by category for fast filtering. */
const SWISS_POIS_BY_CAT = SWISS_POIS.reduce((m, p) => {
  (m[p.cat] = m[p.cat] || []).push(p); return m;
}, {});

/* Helper: index POIs by region. */
const SWISS_POIS_BY_REGION = SWISS_POIS.reduce((m, p) => {
  (m[p.region] = m[p.region] || []).push(p); return m;
}, {});

/* Helper: filter POIs by an array of themes (any-of match). */
function swissPoisWithThemes(themes) {
  const set = new Set(themes);
  return SWISS_POIS.filter(p => p.themes.some(t => set.has(t)));
}

/* Helper: top-N most notable POIs (score >= threshold). */
function swissPoisTop(n = 25, scoreFloor = 8) {
  return SWISS_POIS
    .filter(p => (p.sc || 0) >= scoreFloor)
    .slice()
    .sort((a, b) => (b.sc || 0) - (a.sc || 0))
    .slice(0, n);
}

if (typeof module !== 'undefined') {
  module.exports = { SWISS_POIS, SWISS_POIS_BY_CAT, SWISS_POIS_BY_REGION, swissPoisWithThemes, swissPoisTop };
}
